   161	/* functions for telnet support, when telnet server is loaded */
   162	int coding_setmod_cmd(char *buff, int debug, telnet_printfunc_t prnt)
   163	{
   164	   if (debug > 0)
   165	       prnt( "coding_setmod_cmd received %s\n",buff);
   166	
   167	      if (strcasestr(buff,"sse") != NULL) {
   168	         decoding_setmode(MODE_DECODE_SSE);
   169	      } else if (strcasestr(buff,"avx2") != NULL) {
   170	         decoding_setmode(MODE_DECODE_AVX2);
   171	      } else if (strcasestr(buff,"stdc") != NULL) {
   172	         decoding_setmode(MODE_DECODE_C);
   173	      } else if (strcasestr(buff,"none") != NULL) {
   174	         decoding_setmode(MODE_DECODE_NONE);
   175	      } else {
   176	          prnt("%s: wrong setmod parameter...\n",buff);
   177	      }
   178	   prnt("Coding and decoding current mode: %s\n",modedesc[curmode]);
   179	   return 0;
   180	}

